import{_ as e,o as a,c as l,a2 as n}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"F07: 存貨週轉效率同業對比","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6442_光聖/20260504/F07_存貨週轉效率同業對比.md","filePath":"審計報告庫/財務審計/6442_光聖/20260504/F07_存貨週轉效率同業對比.md"}'),r={name:"審計報告庫/財務審計/6442_光聖/20260504/F07_存貨週轉效率同業對比.md"};function i(s,t,d,o,h,g){return a(),l("div",null,[...t[0]||(t[0]=[n('<h1 id="f07-存貨週轉效率同業對比" tabindex="-1">F07: 存貨週轉效率同業對比 <a class="header-anchor" href="#f07-存貨週轉效率同業對比" aria-label="Permalink to &quot;F07: 存貨週轉效率同業對比&quot;">​</a></h1><blockquote><p>標的公司：6442 光聖 | 基準日期：20260504</p></blockquote><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><hr><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>存貨週轉天數與同業相比是否具備競爭優勢？整體營運週期（Cash Cycle）是否處於擴張狀態？</p><hr><h2 id="🎯-專家直斷-40-80-字" tabindex="-1">🎯 專家直斷（40-80 字） <a class="header-anchor" href="#🎯-專家直斷-40-80-字" aria-label="Permalink to &quot;🎯 專家直斷（40-80 字）&quot;">​</a></h2><ul><li><strong>核心結論</strong>：DIO 347 天同業中偏高（華星光 172 天），營收暴增後策略性囤料所致；現金循環 280 天反映供應鏈效率有改善空間，評級中。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：根據截至 2025 年最新數據</li></ul><hr><h2 id="📊-診斷評級-80-150-字" tabindex="-1">📊 診斷評級（80-150 字） <a class="header-anchor" href="#📊-診斷評級-80-150-字" aria-label="Permalink to &quot;📊 診斷評級（80-150 字）&quot;">​</a></h2><p>光聖 DIO 347 天 vs 華星光 172 天（高 102%）、波若威 287 天（高 21%）、上詮 436 天（低 20%）。在同業中居中段偏上，但考慮到光聖營收三年成長 315%（同業多在 100% 以內），存貨僅增長 100%，存貨增幅遠低於營收增幅。現金循環 280 天高於行業均值，主因為 DPO 僅 123 天 vs 波若威的 318 天，代表光聖對供應商的付款條件較緊，反而反映了較強的議價能力。</p><p><strong>評級：B（持平）</strong> — 存貨週轉效率有待改善，但營收高速成長具備掩蓋效應。</p><hr><h2 id="🔍-答詢詳解-200-450-字" tabindex="-1">🔍 答詢詳解（200-450 字） <a class="header-anchor" href="#🔍-答詢詳解-200-450-字" aria-label="Permalink to &quot;🔍 答詢詳解（200-450 字）&quot;">​</a></h2><h3 id="_1-存貨週轉天數同業階差分析" tabindex="-1">1. 存貨週轉天數同業階差分析 <a class="header-anchor" href="#_1-存貨週轉天數同業階差分析" aria-label="Permalink to &quot;1. 存貨週轉天數同業階差分析&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">公司（代碼）</th><th style="text-align:center;">2024 DIO</th><th style="text-align:center;">2025 DIO</th><th style="text-align:center;">變動</th><th style="text-align:center;">現金循環</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>光聖 6442</strong></td><td style="text-align:center;"><strong>379 天</strong></td><td style="text-align:center;"><strong>347 天</strong></td><td style="text-align:center;"><strong>−32 天 ↓</strong></td><td style="text-align:center;"><strong>280 天</strong></td></tr><tr><td style="text-align:left;">波若威 3163</td><td style="text-align:center;">272 天</td><td style="text-align:center;">287 天</td><td style="text-align:center;">+15 天 ↑</td><td style="text-align:center;">50 天</td></tr><tr><td style="text-align:left;">華星光 4979</td><td style="text-align:center;">162 天</td><td style="text-align:center;">172 天</td><td style="text-align:center;">+10 天 ↑</td><td style="text-align:center;">43 天</td></tr><tr><td style="text-align:left;">上詮 3363</td><td style="text-align:center;">322 天</td><td style="text-align:center;">436 天</td><td style="text-align:center;">+114 天 ↑</td><td style="text-align:center;">286 天</td></tr></tbody></table><p><strong>光聖 DIO 在同業中的定位分析：</strong></p><p>光聖的 DIO（347 天）優於上詮（436 天）但遜於波若威（287 天）和華星光（172 天）。若以「DIO 年減幅度」衡量，光聖年減 32 天是群組中唯一顯著改善的企業；波若威、華星光、上詮的 DIO 均較 2024 年惡化。</p><p>核心差異解釋：</p><ul><li>**華星光（4979）**DIO 僅 172 天，因其產品以光主動元件（光收發模組）為主，生產週期短、周轉快</li><li>**波若威（3163）**DPO 達 318 天（貨到 10 個月後才付款），使其現金循環僅 50 天——這反映供應商議價權而非營運效率</li><li>**上詮（3363）**DIO 惡化至 436 天，顯示存貨堆積壓力最嚴重</li></ul><h3 id="_2-營運週期-dio-dso-趨勢" tabindex="-1">2. 營運週期（DIO + DSO）趨勢 <a class="header-anchor" href="#_2-營運週期-dio-dso-趨勢" aria-label="Permalink to &quot;2. 營運週期（DIO + DSO）趨勢&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">公司</th><th style="text-align:center;">2024 營運週期</th><th style="text-align:center;">2025 營運週期</th><th style="text-align:center;">變動</th></tr></thead><tbody><tr><td style="text-align:left;">光聖</td><td style="text-align:center;">447 天</td><td style="text-align:center;">403 天</td><td style="text-align:center;"><strong>−44 天</strong></td></tr><tr><td style="text-align:left;">波若威</td><td style="text-align:center;">355 天</td><td style="text-align:center;">368 天</td><td style="text-align:center;">+13 天</td></tr><tr><td style="text-align:left;">華星光</td><td style="text-align:center;">205 天</td><td style="text-align:center;">219 天</td><td style="text-align:center;">+14 天</td></tr><tr><td style="text-align:left;">上詮</td><td style="text-align:center;">397 天</td><td style="text-align:center;">490 天</td><td style="text-align:center;">+93 天</td></tr></tbody></table><p>光聖是唯一營運週期顯著縮短的企業（−44 天），主因為 DSO 從 68 降至 56 天、DIO 從 379 降至 347 天。上詮營運週期暴增 93 天是最差的同業表現。</p><h3 id="_3-存貨結構比較的競爭意涵" tabindex="-1">3. 存貨結構比較的競爭意涵 <a class="header-anchor" href="#_3-存貨結構比較的競爭意涵" aria-label="Permalink to &quot;3. 存貨結構比較的競爭意涵&quot;">​</a></h3><p>光聖存貨中原料佔 42.9%、製成品僅 39.1%，而華星光原料佔比較低、製成品佔比較高。原料存貨佔比高代表：</p><ul><li><strong>正面解讀</strong>：對 2026 年訂單持樂觀預期，提前備料確保供應鏈穩定</li><li><strong>負面解讀</strong>：若訂單低於預期，大量原料將面臨呆滯跌價風險</li></ul><hr><h2 id="💡-專家評析-200-450-字" tabindex="-1">💡 專家評析（200-450 字） <a class="header-anchor" href="#💡-專家評析-200-450-字" aria-label="Permalink to &quot;💡 專家評析（200-450 字）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><p><strong>DIO 仍高於多數同業（壓力 ⚠️）</strong>：347 天庫存週轉遠高於華星光 172 天。原料 5.19 億中有多少可對應未來 2-3 季實際訂單高度不確定，若需求放緩，光聖去庫存壓力將大於同業。</p></li><li><p><strong>現金循環 280 天營運資金佔用極高</strong>：進料付款到收款間隔 9 個月，每 1 元營收需鎖定約 0.77 元營運資金。對比波若威 50 天（僅 0.14 元），資金運用效率明顯落後。</p></li><li><p><strong>同業 DIO 普遍惡化預示行業庫存壓力</strong>：波若威、華星光、上詮 DIO 均較 2024 年增加，顯示光通訊行業整體庫存水位上升。</p></li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><p><strong>營收暴增期策略性備料合理</strong>：三年營收增長 315%，維持較高原料庫存是確保供應鏈不斷鏈的合理選擇，隨規模穩定 DIO 有望向 200-250 天收斂。</p></li><li><p><strong>改善速度領先同業</strong>：DIO 年減 32 天、營運週期年減 44 天，改善動能居業界之首，管理層已積極調整庫存效率。</p></li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>光聖存貨效率在高速成長期屬可接受偏高但改善路徑明確。需跟蹤 DIO 能否在 2026 年降至 300 天以下。</p><hr><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>計算工具</strong>：財務分析工具.py (inventory_check 6442 / 3163 / 4979 / 3363)</li><li><strong>原始數據</strong>：FinMind TaiwanStockBalanceSheet + TaiwanStockMonthRevenue + TaiwanStockFinancialStatements</li><li><strong>年報資料</strong>：6442 2025 Q4 合併財報存貨明細附註</li><li><strong>查詢參數</strong>：stock_id=6442,3163,4979,3363, start=2023-01-01, end=2025-12-31</li><li><strong>數據查詢日期</strong>：2026-05-04</li></ul>',38)])])}const y=e(r,[["render",i]]);export{x as __pageData,y as default};
